example.programlisting:
...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (!check_concurrent("$fU")) {
            xlog("L_WARN", "$fU over limit: $var(concurrent_count)/$var(concurrent_limit)\n");
            sl_send_reply(486, "Too Many Calls");
            exit;
        }
        # auto_track handles inc/dec via dialog callbacks
    }
}
...

...
route[reload_limits] {
    if (concurrent_reload()) {
        xlog("L_INFO", "Call limits reloaded successfully\n");
    } else {
        xlog("L_ERR", "Call limits reload failed\n");
    }
}
...

...
route {
    if (is_method("INVITE") && !has_totag()) {
        if (check_burst("$fU")) {
            xlog("L_WARN", "Burst detected for $fU: delta=$var(burst_delta)\n");
        }
    }
}
...

...
route[set_limit] {
    concurrent_set_limit("alice", "20");
    xlog("L_INFO", "alice limit overridden to 20\n");
}
...

